{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding a sequence of sibling merges to transform one tree into another. This involves identifying which nodes in the initial tree must be merged to match the structure and node values of the final tree, while respecting the rule that only siblings can be merged and the larger value is preserved.",
  "helpers": [
    {
      "label": "tree_structure_analyzer",
      "instructions": "Analyze the initial tree and the final tree to identify the mapping between nodes. Specifically, for each node in the final tree, identify which set of nodes in the initial tree (its ancestors or siblings) must have been merged to form it. Determine the parent-child relationships in both trees and identify which nodes in the initial tree are 'lost' due to merging."
    },
    {
      "label": "merge_sequence_generator",
      "instructions": "Given the mapping of initial nodes to final nodes, construct a valid sequence of merge operations. A merge operation is valid if it involves two siblings in the current state of the tree. The sequence must ensure that when two nodes are merged, the resulting node has the correct value (the maximum of the two) and the correct set of children as required by the final tree structure. Ensure the order of merges respects the tree hierarchy (e.g., merging children before merging their parents)."
    }
  ],
  "synthesis_brief": "Combine the structural mapping from the analyzer with the ordered sequence from the generator to produce the final list of merge operations. Verify that the sequence of merges is valid according to the problem rules: only siblings can be merged, and the larger value is kept."
}

